/**
 * Stray Kids Photos — official JYP gallery (straykids.jype.com/Default/Gallery).
 * Manifest is generated by `npm run fetch:skz-gallery` (all 46 paginated pages).
 */
import galleryManifest from './strayKidsGallery.generated.json'
import { resolveJypeImageUrl } from '@/utils/jypeImageUrl'

export const JYPE_SITE = 'https://straykids.jype.com'
export const JYPE_GALLERY = galleryManifest.source

/** How many Stray Kids Photos appear per picker page. */
export const STRAY_KIDS_PHOTOS_PER_PAGE = 8

function displayName(raw) {
  const text = raw.replace(/\.(jpe?g|png|webp)$/i, '').trim()
  return text || 'Gallery photo'
}

export const STRAY_KIDS_PHOTOS = galleryManifest.photos.map((entry) => ({
  id: entry.id,
  name: displayName(entry.name),
  image: resolveJypeImageUrl(entry.jypeUrl),
  jypeUrl: entry.jypeUrl,
  credit: 'straykids.jype.com',
}))

export const STRAY_KIDS_PHOTO_COUNT = STRAY_KIDS_PHOTOS.length
